/*
 * Requires:
 *   "a" and "b" are valid pointers to file_record structures.
 *
 * Effects:
 *   Comparison function for qsort to sort file records by filename
 *   in ASCIIbetical order.
 */
static int
compare_records(const void *a, const void *b)
{
    const struct file_record *rec_a = (const struct file_record *)a;
    const struct file_record *rec_b = (const struct file_record *)b;
    return strcmp(rec_a->name, rec_b->name);
}

/*
 * Requires:
 *   "input_files" is a valid array of file name strings.
 *   "nfiles" is the number of files in the array.
 *
 * Effects:
 *   Counts characters, words, and/or lines in each file based on flags.
 *   Prints results for each file in ASCIIbetical order.
 *   Prints totals at the end.
 *   Returns 0 on success, 1-255 on error.
 */
static int
do_count(char *input_files[], const int nfiles,
    const bool char_flag, const bool word_flag,
    const bool line_flag, const bool test_flag)
{
    (void)test_flag; /* Suppress unused parameter warning */

    int error_flag = 0;
    struct counts total = {0, 0, 0};

    /* Allocate array to hold file records for sorting */
    struct file_record *records = (struct file_record *)malloc(
        nfiles * sizeof(struct file_record));
    if (records == NULL) {
        app_error_fmt("Cannot allocate memory");
        return 1;
    }

    /* Process each file */
    for (int i = 0; i < nfiles; i++) {
        records[i].name = input_files[i];
        records[i].cnts.chars = 0;
        records[i].cnts.words = 0;
        records[i].cnts.lines = 0;
        records[i].valid = false;

        FILE *fp = fopen(input_files[i], "r");
        if (fp == NULL) {
            app_error_fmt("cannot open file '%s'", input_files[i]);
            error_flag = 1;
            continue;
        }

        /* Read file and count chars, words, lines */
        int c;
        bool in_word = false;

        while ((c = fgetc(fp)) != EOF) {
            records[i].cnts.chars++;

            if (c == '\n') {
                records[i].cnts.lines++;
                in_word = false;
            } else if (isspace(c)) {
                in_word = false;
            } else {
                /* Non-whitespace character */
                if (!in_word) {
                    records[i].cnts.words++;
                    in_word = true;
                }
            }
        }

        /* Check for read errors */
        if (ferror(fp)) {
            app_error_fmt("cannot read file '%s'", input_files[i]);
            error_flag = 1;
            fclose(fp);
            continue;
        }

        fclose(fp);
        records[i].valid = true;

        /* Add to totals */
        total.chars += records[i].cnts.chars;
        total.words += records[i].cnts.words;
        total.lines += records[i].cnts.lines;
    }

    /* Sort records by filename */
    qsort(records, nfiles, sizeof(struct file_record), compare_records);

    /* Print counts for each file */
    for (int i = 0; i < nfiles; i++) {
        if (records[i].valid) {
            print_counts(stdout, &records[i].cnts, records[i].name,
                char_flag, word_flag, line_flag);
        }
    }

    /* Print totals (always print all three counts) */
    print_counts(stdout, &total, "total", true, true, true);

    /* Free allocated memory */
    free(records);

    return error_flag;
}

